import{C as i,o as n,c as l,a5 as a,E as r}from"./chunks/framework.CW28V7p_.js";const d=JSON.parse('{"title":"2. Snapshots — fetch, create, serve","description":"","frontmatter":{},"headers":[],"relativePath":"module-10/2-snapshots.md","filePath":"module-10/2-snapshots.md","lastUpdated":1780937944000}'),o={name:"module-10/2-snapshots.md"},k=Object.assign(o,{setup(h){const e={id:"m10-2-snapshots",title:"🧠 Mini-check: Snapshots",intro:"2 питання.",questions:[{type:"compare",q:"Full snapshot vs incremental snapshot?",ideal:`Full snapshot: complete accountsDB state at specific slot. Large (~80-100 GB mainnet). Created periodically (every ~25000 slots).

Incremental snapshot: delta from last full. Small (~1 GB typical). Created more frequently (every ~100 slots).

Fast catch-up:
1. Download recent full snapshot (~30-60 min)
2. Download recent incremental delta (~few min)
3. Apply delta до full → current state
4. Catch-up з cluster для recent slots

Total: ~30-90 min vs full replay from genesis (days/weeks).`,explanation:"Module 10.2."},{type:"command",q:"Як list local snapshots ledger directory?",accepts:["ls -lh /home/solana/solana/ledger/snapshot-*","sudo ls -lh /home/solana/solana/ledger/snapshot-*"],ideal:"sudo ls -lh /home/solana/solana/ledger/snapshot-*",explanation:"Module 10.2."}]};return(p,s)=>{const t=i("Quiz");return n(),l("div",null,[s[0]||(s[0]=a(`<h1 id="_2-snapshots-—-fetch-create-serve" tabindex="-1">2. Snapshots — fetch, create, serve <a class="header-anchor" href="#_2-snapshots-—-fetch-create-serve" aria-label="Permalink to &quot;2. Snapshots — fetch, create, serve&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Validators periodically create <strong>snapshots</strong> — compressed accountsDB state dumps at specific slots. Two types: <strong>full</strong> (complete, ~80-100GB mainnet) і <strong>incremental</strong> (delta, ~1GB). Used для fast catch-up — replace days of replay з minutes of download.</p><h2 id="why-snapshots" tabindex="-1">Why snapshots <a class="header-anchor" href="#why-snapshots" aria-label="Permalink to &quot;Why snapshots&quot;">​</a></h2><p>Without snapshots, new validator catching up = replay every TX від genesis. Mainnet has ~1B+ TXs total. Replay would take days/weeks.</p><p>З snapshots:</p><ol><li>Download recent full + incremental з cluster</li><li>Reconstruct state</li><li>Catch-up з cluster only для recent slots (minutes)</li></ol><p>Total ~30-90 min vs days.</p><h2 id="snapshot-files" tabindex="-1">Snapshot files <a class="header-anchor" href="#snapshot-files" aria-label="Permalink to &quot;Snapshot files&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ledger/</span></span>
<span class="line"><span>├── snapshot-369000000-XYZ.tar.zst       # full snapshot at slot 369M (~80GB)</span></span>
<span class="line"><span>├── snapshot-369450000-XYZ.tar.zst       # full at slot 369.45M</span></span>
<span class="line"><span>├── incremental-snapshot-369450000-369450100-ABC.tar.zst  # delta from 369450000 to 369450100</span></span>
<span class="line"><span>├── incremental-snapshot-369450100-369450200-DEF.tar.zst</span></span>
<span class="line"><span>└── ...</span></span></code></pre></div><p>Compressed з <strong>zstd</strong>. Tar archives contain all account state plus metadata.</p><h3 id="frequencies" tabindex="-1">Frequencies <a class="header-anchor" href="#frequencies" aria-label="Permalink to &quot;Frequencies&quot;">​</a></h3><p>Mainnet defaults:</p><ul><li><strong>Full snapshot</strong>: every 25,000 slots (~3 годин)</li><li><strong>Incremental</strong>: every 100 slots (~40 секунд)</li></ul><p>Settings configurable via flags:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">agave-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --full-snapshot-interval-slots</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 25000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --incremental-snapshot-interval-slots</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span></span></code></pre></div><h3 id="serve-до-peers" tabindex="-1">Serve до peers <a class="header-anchor" href="#serve-до-peers" aria-label="Permalink to &quot;Serve до peers&quot;">​</a></h3><p>Validator може serve snapshots для cluster:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">agave-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --rpc-port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8899</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --enable-rpc-transaction-history</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --enable-extended-tx-metadata-storage</span></span></code></pre></div><p>Other validators fetching snapshots reach це через gossip-known RPC ports.</p><h3 id="manual-snapshot-creation" tabindex="-1">Manual snapshot creation <a class="header-anchor" href="#manual-snapshot-creation" aria-label="Permalink to &quot;Manual snapshot creation&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">agave-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-snapshot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">SLO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Useful для backup перед major operations.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="cluster-restart-cheatsheet-§3" tabindex="-1">Cluster restart (cheatsheet §3) <a class="header-anchor" href="#cluster-restart-cheatsheet-§3" aria-label="Permalink to &quot;Cluster restart (cheatsheet §3)&quot;">​</a></h3><p>After Phase 1 (wipe ledger), new validator starts WITHOUT snapshot. Must fetch fresh з cluster — connects to entrypoints, requests snapshot, downloads, reconstructs.</p><p>Fetch може bу від:</p><ul><li>Other operators (gossip-discovered, fastest якщо близькі)</li><li>Public mirrors (some providers host snapshots)</li></ul><h3 id="snapshot-integrity-verification" tabindex="-1">Snapshot integrity verification <a class="header-anchor" href="#snapshot-integrity-verification" aria-label="Permalink to &quot;Snapshot integrity verification&quot;">​</a></h3><p>Validator verifies downloaded snapshot integrity (hash check). If corrupted → re-fetch.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Logs показують snapshot fetching progress</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> snapshot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,32)),r(t,{data:e}),s[1]||(s[1]=a('<h2 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h2><p><a href="/glossary#s"><code>Snapshot</code></a>, <a href="/glossary#f"><code>Full snapshot</code></a>, <a href="/glossary#i"><code>Incremental snapshot</code></a>, <a href="/glossary#z"><code>zstd</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/operations/best-practices/general" target="_blank" rel="noreferrer">Anza: Snapshots</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-10/1-geyser-rpc">← 1. Geyser/RPC</a> | <strong>Наступне:</strong> <a href="/module-10/3-doublezero">3. DoubleZero →</a></p>',6))])}}});export{d as __pageData,k as default};
